refentry.refsect1:
&reftitle.description;
boolarray_all arraydizi callableişlev
array_all, belirtilen işlev geriçağırım işlevi tüm elemanlar için &true; döndürürse &true; döndürür. Aksi takdirde &false; döndürür.

&reftitle.returnvalues;

 işlev geriçağırım işlevi tüm elemanlar için &true;
 döndürürse &true;, aksi takdirde &false; döndürür.

  &reftitle.examples;

   array_all örneği


<?php
$array = [
    'a' => 'dog',
    'b' => 'cat',
    'c' => 'cow',
    'd' => 'duck',
    'e' => 'goose',
    'f' => 'elephant'
];

// Tüm hayvan isimleri 12 harften kısa mı diye sınar.
var_dump(array_all($array, function (string $value) {
    return strlen($value) < 12;
}));

// Tüm hayvan isimleri 5 harften uzun mu diye sınar.
var_dump(array_all($array, function (string $value) {
    return strlen($value) > 5;
}));

// Dizi anahtarlarının tümü dizge mi diye sınar.
var_dump(array_all($array, function (string $value, $key) {
   return is_string($key);
}));
?>


   &example.outputs;


bool(true)
bool(false)
bool(true)
